  /// Generate a filename with timestamp and format extension
  String generateFilename({
    String prefix = 'fractal',
    required ExportFormat format,
    String? fractalType,
  }) {
    return ExportFilenameParts(
      prefix: prefix,
      format: format,
      fractalType: fractalType,
      timestampMillis: DateTime.now().millisecondsSinceEpoch,
    ).filename;
  }

  Future<File> saveBytes(Uint8List bytes, {required String filename}) async {
    final file = await createExportFile(filename: filename);
    final written = await file.writeAsBytes(bytes, flush: true);
    await _mirrorImageToMediaStoreIfNeeded(bytes, filename);
    return written;
  }

  Future<void> shareFile(File file, {String? text}) async {
    await Share.shareXFiles([XFile(file.path)], text: text);
  }

  bool _isImageFilename(String filename) {
    final lower = filename.toLowerCase();
    return lower.endsWith('.png') ||
        lower.endsWith('.jpg') ||
        lower.endsWith('.jpeg') ||
        lower.endsWith('.gif') ||
        lower.endsWith('.webp');
  }

  String _mimeTypeForFilename(String filename) {
    final lower = filename.toLowerCase();
    if (lower.endsWith('.jpg') || lower.endsWith('.jpeg')) {
      return 'image/jpeg';
    }
    if (lower.endsWith('.webp')) {
      return 'image/webp';
    }
    if (lower.endsWith('.gif')) {
      return 'image/gif';
    }
    return 'image/png';
  }

  Future<void> _mirrorImageToMediaStoreIfNeeded(
    Uint8List bytes,
    String filename,
  ) async {
    if (kIsWeb || !Platform.isAndroid || !_isImageFilename(filename)) {
      return;
    }

    try {
      await _mediaStoreChannel.invokeMethod<String>('saveImage', {
        'bytes': bytes,
        'filename': filename,
        'mimeType': _mimeTypeForFilename(filename),
      });
    } catch (_) {
      // Best-effort only: keep local export path working even if MediaStore fails.
    }
  }

  /// Export with full options and sharing
  Future<ExportResult> exportWithOptions(
    GlobalKey boundaryKey, {
    required ExportOptions options,
    required double screenWidth,
    required double screenHeight,
    required String fractalType,
    required Map<String, Object> parameters,
    void Function(double progress)? onProgress,
  }) async {
    // Create metadata if embedding is enabled
    final metadata = options.embedMetadata
        ? ExportMetadata(
            fractalType: fractalType,
            parameters: parameters,
            createdAt: DateTime.now(),
          )
        : null;

    final effectiveFormat = resolveEffectiveFormat(options.format);

    final finalOptions = options.copyWith(
      metadata: metadata,
      format: effectiveFormat,
    );

    // Capture and process the image
    final bytes = await captureWithOptions(
      boundaryKey,
      options: finalOptions,
      screenWidth: screenWidth,
      screenHeight: screenHeight,
      onProgress: onProgress,
    );

    // Generate filename and save
    final filename = generateFilename(
      format: effectiveFormat,
      fractalType: fractalType,
    );

    final file = await saveBytes(bytes, filename: filename);
    final targetDims =
        finalOptions.getTargetDimensions(screenWidth, screenHeight);

    return ExportResult(
      file: file,
      format: effectiveFormat,
      width: targetDims.$1,
      height: targetDims.$2,
      fileSize: bytes.length,
    );
  }
}

/// Result of an export operation
class ExportResult {
  final File file;
  final ExportFormat format;
  final int width;
  final int height;
  final int fileSize;

  const ExportResult({
    required this.file,
    required this.format,
    required this.width,
    required this.height,
    required this.fileSize,
  });

  String get formattedSize {
    if (fileSize < 1024) {
      return '$fileSize B';
    } else if (fileSize < 1024 * 1024) {
      return '${(fileSize / 1024).toStringAsFixed(1)} KB';
    } else {
      return '${(fileSize / (1024 * 1024)).toStringAsFixed(1)} MB';
    }
  }

  String get resolution => '$width×$height';
}

import 'package:flutter/material.dart';

/// Video export format.
enum VideoExportFormat {
  mp4('MP4', 'mp4'),
  gif('GIF', 'gif');

  final String label;
  final String extension;
  const VideoExportFormat(this.label, this.extension);

  String get displayName => label;
}

/// Animation type for video export.
enum VideoAnimationType {
  zoomIn('Zoom In', Icons.zoom_in),
  zoomOut('Zoom Out', Icons.zoom_out),
  rotate('Rotate', Icons.rotate_right),
  pan('Pan', Icons.pan_tool),
  parameterSweep('Parameter Sweep', Icons.tune),
  custom('Custom', Icons.settings);

  final String label;
  final IconData icon;
  const VideoAnimationType(this.label, this.icon);
}

/// Video resolution presets.
enum VideoResolution {
  sd(480, 'SD (480p)'),
  hd(720, 'HD (720p)'),
  fullHd(1080, 'Full HD (1080p)'),
  qhd(1440, 'QHD (1440p)');

  final int height;
  final String label;
  const VideoResolution(this.height, this.label);

  int get width => (height * 16 / 9).round();
}

/// Frame rate options.
enum VideoFrameRate {
  fps15(15),
  fps24(24),
  fps30(30),
  fps60(60);

  final int fps;
  const VideoFrameRate(this.fps);

  String get label => '$fps fps';
}

/// Replayable frame-count contract for video export durations.
class _VideoFrameCountPolicy {
  static const int minFrames = 1;
  static const int _microsecondsPerSecond = Duration.microsecondsPerSecond;

  const _VideoFrameCountPolicy._();

  /// Converts a duration and frame rate into the number of frames to render.
  ///
  /// Fractional-second durations must not be truncated to zero frames; even a
  /// zero or invalid negative duration remains replayable as a single frame.
  static int fromDurationAndFrameRate({
    required Duration duration,
    required VideoFrameRate frameRate,
  }) {
    final microseconds = duration.inMicroseconds;
    if (microseconds <= 0) return minFrames;

    final scaledFrames = microseconds * frameRate.fps;
    final frameCount =
        (scaledFrames + _microsecondsPerSecond - 1) ~/ _microsecondsPerSecond;
    return frameCount < minFrames ? minFrames : frameCount;
  }
}

/// Quality presets.
enum VideoQualityPreset {
  draft('Draft', 0.5),
  standard('Standard', 0.7),
  high('High', 0.85),
  maximum('Maximum', 1.0);

  final String label;
  final double quality;
  const VideoQualityPreset(this.label, this.quality);
}

/// Animation easing functions.
enum AnimationEasing {
  linear('Linear'),
  easeIn('Ease In'),
  easeOut('Ease Out'),
  easeInOut('Ease In-Out');

  final String label;
  const AnimationEasing(this.label);

  double apply(double t) {
    return switch (this) {
      AnimationEasing.linear => t,
      AnimationEasing.easeIn => t * t,
      AnimationEasing.easeOut => 1 - (1 - t) * (1 - t),
      AnimationEasing.easeInOut =>
        t < 0.5 ? 2 * t * t : 1 - (-2 * t + 2) * (-2 * t + 2) / 2,
    };
  }
}

/// Configuration for parameter sweep animation.
class ParameterSweepConfig {
  final String parameterId;
  final double startValue;
  final double endValue;
  final bool pingPong;

  const ParameterSweepConfig({
    required this.parameterId,
    required this.startValue,
    required this.endValue,
    this.pingPong = false,
  });
}

/// Video export configuration options.
class VideoExportOptions {
  /// Copy-with sentinel so nullable fields can distinguish omitted from null.
  static const Object _unset = Object();

  final VideoExportFormat format;
  final VideoAnimationType animationType;
  final VideoResolution resolution;
  final VideoFrameRate frameRate;
  final VideoQualityPreset quality;
  final AnimationEasing easing;
  final Duration duration;
  final double zoomFactor;
  final ParameterSweepConfig? parameterSweep;
  final bool loop;
  final bool includeWatermark;

  const VideoExportOptions({
    this.format = VideoExportFormat.mp4,
    this.animationType = VideoAnimationType.zoomIn,
    this.resolution = VideoResolution.fullHd,
    this.frameRate = VideoFrameRate.fps30,
    this.quality = VideoQualityPreset.high,
    this.easing = AnimationEasing.easeInOut,
    this.duration = const Duration(seconds: 5),
    this.zoomFactor = 10.0,
    this.parameterSweep,
    this.loop = false,
    this.includeWatermark = false,
  });

  VideoExportOptions copyWith({
    VideoExportFormat? format,
    VideoAnimationType? animationType,
    VideoResolution? resolution,
    VideoFrameRate? frameRate,
    VideoQualityPreset? quality,
    AnimationEasing? easing,
    Duration? duration,
    double? zoomFactor,
    Object? parameterSweep = _unset,
    bool? loop,
    bool? includeWatermark,
  }) {
    assert(
      identical(parameterSweep, _unset) ||
          parameterSweep == null ||
          parameterSweep is ParameterSweepConfig,
      'parameterSweep must be a ParameterSweepConfig? value',
    );

    return VideoExportOptions(
      format: format ?? this.format,
      animationType: animationType ?? this.animationType,
      resolution: resolution ?? this.resolution,
      frameRate: frameRate ?? this.frameRate,
      quality: quality ?? this.quality,
      easing: easing ?? this.easing,
      duration: duration ?? this.duration,
      zoomFactor: zoomFactor ?? this.zoomFactor,
      parameterSweep: identical(parameterSweep, _unset)
          ? this.parameterSweep
          : parameterSweep as ParameterSweepConfig?,
      loop: loop ?? this.loop,
      includeWatermark: includeWatermark ?? this.includeWatermark,
    );
  }

  int get totalFrames => _VideoFrameCountPolicy.fromDurationAndFrameRate(
        duration: duration,
        frameRate: frameRate,
      );

  /// Estimated file size in MB (rough approximation).
  double get estimatedSizeMb {
    final pixels = resolution.width * resolution.height;
    final bitsPerPixel = format == VideoExportFormat.gif ? 8.0 : 0.15;
    return (pixels * bitsPerPixel * totalFrames) / 8 / 1024 / 1024;
  }
}

/// Preset configurations for quick selection.
class VideoExportPresets {
  static const socialQuick = VideoExportOptions(
    format: VideoExportFormat.gif,
    resolution: VideoResolution.sd,
    frameRate: VideoFrameRate.fps15,
    duration: Duration(seconds: 3),
    quality: VideoQualityPreset.standard,
  );

  static const socialMp4 = VideoExportOptions(
    format: VideoExportFormat.mp4,
    resolution: VideoResolution.hd,
    frameRate: VideoFrameRate.fps30,
    duration: Duration(seconds: 5),
    quality: VideoQualityPreset.high,
  );

  static const highQuality = VideoExportOptions(
    format: VideoExportFormat.mp4,
    resolution: VideoResolution.fullHd,
    frameRate: VideoFrameRate.fps60,
    duration: Duration(seconds: 10),
    quality: VideoQualityPreset.maximum,
  );

  static const gifLoop = VideoExportOptions(
    format: VideoExportFormat.gif,
    resolution: VideoResolution.sd,
    frameRate: VideoFrameRate.fps24,
    duration: Duration(seconds: 4),
    loop: true,
  );
}

